import{_ as t,o as i,c as a,ak as r}from"./chunks/framework.DkeEmzcj.js";const u=JSON.parse('{"title":"WhatsZip Viewer","description":"Effortlessly view your exported WhatsApp chats including photos, videos, and audio — all offline and privately.","frontmatter":{"title":"WhatsZip Viewer","description":"Effortlessly view your exported WhatsApp chats including photos, videos, and audio — all offline and privately."},"headers":[],"relativePath":"whatszip-viewer/index.md","filePath":"whatszip-viewer/index.md","lastUpdated":1772239018000}'),s={name:"whatszip-viewer/index.md"};function o(l,e,n,d,p,h){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="whatszip-viewer" tabindex="-1">WhatsZip Viewer <a class="header-anchor" href="#whatszip-viewer" aria-label="Permalink to “WhatsZip Viewer”">​</a></h1><p>Effortlessly view your exported WhatsApp chats including photos, videos, and audio — all offline and privately.</p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to “Key Features”">​</a></h2><ul><li><strong>Complete Privacy:</strong> All your chat data is processed locally on your device. Nothing is uploaded to any servers.</li><li><strong>Full Media Support:</strong> View attached photos, play videos, and listen to audio messages directly within the app.</li><li><strong>Interactive Links:</strong> Clickable links within your chat messages open directly in your external browser.</li><li><strong>Easy Navigation:</strong> Scroll through your entire chat history with a familiar interface.</li><li><strong>Mobile Friendly:</strong> Designed for seamless experience on all mobile devices.</li><li><strong>System Messages Display:</strong> Clearly distinguish system messages (e.g., group creations, members added/removed) from regular chats.</li></ul><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to “How It Works”">​</a></h2><ol><li><strong>Export Chat from WhatsApp:</strong> In WhatsApp, go to a chat, tap “More Options” &gt; “More” &gt; “Export chat” and select “Include media”.</li><li><strong>Select Zip in App:</strong> Open WhatsZip Viewer, tap the “+” button, and select the exported <code>.zip</code> file from your device.</li><li><strong>View Your Chat:</strong> Your chat history, including all media, will be displayed instantly within the app.</li></ol>',6)])])}const g=t(s,[["render",o]]);export{u as __pageData,g as default};
